$c=Canvas; $g=$c.g; Title $g '01' 'Kiến trúc tổng thể' 'Hai sender gửi dữ liệu về một receiver; receiver đóng vai trò gateway lên CoreIoT.'; Panel $g 120 220 380 260 'Sender A' @('Mô phỏng cảm biến','Suy luận TinyML tại edge','Web UI cục bộ','Gửi telemetry qua TCP') $theme.lgreen $theme.green; Panel $g 120 760 380 240 'Sender B' @('Mô phỏng cảm biến độc lập','Threshold riêng','Nhận config và gửi ACK','Gửi telemetry qua TCP') $theme.lgreen $theme.green; Panel $g 760 260 520 360 'Receiver gateway' @('TCP server nhận nhiều sender','Quản lý known / unknown device','Đồng bộ threshold hai chiều','Web UI quản trị','MQTT gateway lên CoreIoT') $theme.lblue $theme.blue; Panel $g 1520 300 520 280 'CoreIoT / Cloud' @('Lưu telemetry','Lưu attribute threshold','Hiển thị dashboard','Gọi RPC từ xa') $theme.lorange $theme.orange; Panel $g 760 760 520 180 'Control plane' @('UI receiver hoặc RPC cloud','Tạo gói config','Sender phản hồi config_ack') $theme.lred $theme.red; Arrow $g 500 340 760 380 $theme.green; Badge $g 630 300 'Telemetry JSON'; Arrow $g 500 860 760 520 $theme.green; Badge $g 630 690 'Telemetry JSON'; Arrow $g 1280 420 1520 420 $theme.blue; Badge $g 1400 365 'MQTT gateway'; Arrow $g 760 840 500 870 $theme.red 'Dash'; Badge $g 625 915 'Config + ACK'; Arrow $g 760 800 500 390 $theme.red 'Dash'; Badge $g 625 575 'Config + ACK'; Save $c '01_kien_truc_tong_the.png'
$c=Canvas; $g=$c.g; Title $g '02' 'Sơ đồ mạng nội bộ' 'Receiver vừa giữ vai trò AP nội bộ vừa kết nối Wi-Fi ra ngoài; sender suy ra IP receiver ở host .100.'; Panel $g 120 260 440 260 'Sender' @('SoftAP riêng để cấu hình','STA kết nối vào mạng của receiver','Suy ra địa chỉ receiver','Gửi TCP tới cổng nội bộ') $theme.lgreen $theme.green; Panel $g 820 220 560 340 'Receiver' @('Phát SoftAP cho cấu hình cục bộ','Kết nối STA ra router','Nhận TCP từ sender','Publish MQTT qua internet') $theme.lblue $theme.blue; Panel $g 1600 260 420 220 'Router / Internet' @('Cấp mạng ngoài','Đưa receiver lên cloud') $theme.lorange $theme.orange; Panel $g 820 760 560 180 'Quy ước địa chỉ' @('Sender đổi host hiện tại sang .100','Không cần hard-code toàn bộ IP','Phù hợp mô hình demo /24') $theme.lgray $theme.border; Arrow $g 560 360 820 360 $theme.green; Badge $g 690 305 'TCP telemetry'; Arrow $g 1380 370 1600 370 $theme.blue; Badge $g 1490 310 'MQTT / Wi-Fi STA'; Arrow $g 1040 560 1040 760 $theme.purple; Badge $g 1180 660 'Suy luận host .100'; Save $c '02_so_do_mang_noi_bo.png'
$c=Canvas; $g=$c.g; Title $g '03' 'Module của sender' 'Sender được chia thành các khối độc lập để dễ thay thế và bảo trì.'; $cards=@(@{x=100;y=260;w=360;h=230;t='State + Config';l=@('deviceId','threshold','Wi-Fi','device name');f=$theme.lblue;b=$theme.blue},@{x=560;y=220;w=360;h=310;t='Data + AI';l=@('Mô phỏng nhiệt độ / độ ẩm','Tiền xử lý đầu vào','Suy luận TinyML','Sinh ai_score, ai_status');f=$theme.lgreen;b=$theme.green},@{x=1020;y=260;w=360;h=230;t='Transport';l=@('TCP client','Đóng gói telemetry','Nhận config','Gửi config_ack');f=$theme.lorange;b=$theme.orange},@{x=1480;y=220;w=360;h=310;t='Local UX';l=@('SoftAP + STA','Web UI cục bộ','Hiển thị trạng thái','Lưu LittleFS');f=$theme.lred;b=$theme.red}); foreach($card in $cards){ Panel $g $card.x $card.y $card.w $card.h $card.t $card.l $card.f $card.b }; for($i=0;$i -lt $cards.Count-1;$i++){ Arrow $g ($cards[$i].x+$cards[$i].w) ($cards[$i].y+($cards[$i].h/2)) $cards[$i+1].x ($cards[$i+1].y+($cards[$i+1].h/2)) $theme.border }; Save $c '03_module_sender.png'
$c=Canvas; $g=$c.g; Title $g '04' 'Module của receiver' 'Receiver gom nhiều vai trò gateway nhưng vẫn tách theo tầng trách nhiệm.'; $cards=@(@{x=100;y=260;w=360;h=250;t='Runtime';l=@('Scheduler nền','Kiểm tra timeout','Snapshot định kỳ','Quản lý vòng đời sender');f=$theme.lblue;b=$theme.blue},@{x=560;y=220;w=360;h=330;t='TCP + Registry';l=@('TCP server','Known / unknown sender','Parse packet','SenderState trung tâm');f=$theme.lgreen;b=$theme.green},@{x=1020;y=220;w=360;h=330;t='Cloud Gateway';l=@('MQTT connect/disconnect','Telemetry / attributes','RPC callback','Response về cloud');f=$theme.lorange;b=$theme.orange},@{x=1480;y=260;w=360;h=250;t='Web + Storage';l=@('Web UI quản trị','WebSocket snapshot','LittleFS config','Lưu receiver settings');f=$theme.lred;b=$theme.red}); foreach($card in $cards){ Panel $g $card.x $card.y $card.w $card.h $card.t $card.l $card.f $card.b }; for($i=0;$i -lt $cards.Count-1;$i++){ Arrow $g ($cards[$i].x+$cards[$i].w) ($cards[$i].y+($cards[$i].h/2)) $cards[$i+1].x ($cards[$i+1].y+($cards[$i+1].h/2)) $theme.border }; Save $c '04_module_receiver.png'
$c=Canvas; $g=$c.g; Title $g '07' 'Pipeline TinyML trên sender' 'Từng bước tiền xử lý và suy luận được tách riêng để dễ diễn giải trong báo cáo.'; Panel $g 80 320 360 220 'Dữ liệu đầu vào' @('Nhiệt độ','Độ ẩm','Chuẩn hóa về vector đầu vào') $theme.lblue $theme.blue; Panel $g 500 320 360 220 'Tensor input' @('Ghi dữ liệu vào input tensor','Đúng thứ tự đặc trưng') $theme.lgreen $theme.green; Panel $g 920 280 420 300 'TFLite Micro' @('Interpreter','Arena bộ nhớ','Invoke mô hình') $theme.lorange $theme.orange; Panel $g 1400 320 360 220 'Kết quả AI' @('ai_score','ai_status','Ngưỡng threshold hiện tại') $theme.lred $theme.red; Arrow $g 440 430 500 430 $theme.border; Arrow $g 860 430 920 430 $theme.border; Arrow $g 1340 430 1400 430 $theme.border; Save $c '07_pipeline_ai_inference.png'
$c=Canvas; $g=$c.g; Title $g '08' 'Cấu trúc logic mô hình TFLite' 'Mô hình ở mức báo cáo chỉ cần làm rõ đầu vào, suy luận và đầu ra.'; Panel $g 140 380 420 220 'Input features' @('temperature','humidity') $theme.lblue $theme.blue; Panel $g 820 330 520 320 'Mô hình TinyML' @('Nhận vector 2 đặc trưng','Suy luận điểm bất thường','Chạy tại edge trên ESP32') $theme.lorange $theme.orange; Panel $g 1600 380 420 220 'Output' @('ai_score','NORMAL / ANOMALY') $theme.lgreen $theme.green; Arrow $g 560 490 820 490 $theme.border; Arrow $g 1340 490 1600 490 $theme.border; Save $c '08_cau_truc_model_tflite.png'
